SELECT ?player ?playerLabel WHERE {
  ?player p:P54 ?statement.
  ?statement ps:P54 wd:Q12840.
  ?statement pq:P39 wd:Q5733.
  ?statement pq:P580 ?start.
  ?statement pq:P582 ?end.
  FILTER (math:year(?start) <= 2023 && math:year(?end) >= 2023)
  OPTIONAL { ?player rdfs:label ?playerLabel filter (lang(?playerLabel) = "en") }
}

SELECT ?player ?playerLabel WHERE {
  # Part 1: Existing end date for QB position
  ?player p:P54 ?statement .
  ?statement ps:P54 wd:Q12840 .
  ?statement pq:P39 wd:Q5733 .
  ?statement pq:P580 ?start .
  ?statement pq:P582 ?end .
  FILTER(?start <= "2023-12-31"^^xsd:date)
  FILTER(?end >= "2023-01-01"^^xsd:date)

  OPTIONAL { ?player rdfs:label ?playerLabel FILTER (lang(?playerLabel) = "en") }
}
UNION
{
  # Part 2: No end date (active QB)
  ?player p:P54 ?statement .
  ?statement ps:P54 wd:Q12840 .
  ?statement pq:P39 wd:Q5733 .
  ?statement pq:P580 ?start .
  FILTER(?start <= "2023-12-31"^^xsd:date)
  FILTER NOT EXISTS { ?statement pq:P582 ?end }

  OPTIONAL { ?player rdfs:label ?playerLabel FILTER (lang(?playerLabel) = "en") }
} LIMIT 1

