SELECT ?player ?playerLabel WHERE {
  ?player wdt:P39 wd:Q5733 .
  ?player wdt:P54 wd:Q12840 .
  OPTIONAL { ?player rdfs:label ?playerLabel FILTER (lang(?playerLabel) = "en") }
  ?player p:P39 ?positionStatement.
  ?positionStatement ps:P39 wd:Q5733.
  ?positionStatement pq:P580 ?startDate.
  OPTIONAL { ?positionStatement pq:P582 ?endDate. }
  FILTER (?startDate <= "2023-12-31"^^xsd:date)
  FILTER ((BOUND(?endDate) && ?endDate >= "2023-01-01"^^xsd:date) || !BOUND(?endDate))
} LIMIT 1

